// Formatear input para WhatsApp
const wppData = $('une_data_wpp').first().json;

//const memoria_contexto_array = $input.first().json.ChatMemory
//const etapa_actual = memoria_contexto_array[memoria_contexto_array.length-1].etapa
// const etapa_actual = memoria_contexto_array.length > 0 ? memoria_contexto_array[memoria_contexto_array.length-1].etapa : null;
// CONVERTIR ARRAY A TEXTO PLANO para que el AI Agent lo reconozca
// let memoria_contexto = "";
// if (memoria_contexto_array && memoria_contexto_array.length > 0) {
//   memoria_contexto = memoria_contexto_array
//     .map(item => `${item.created_at}: ${item.mensaje}`)
//     .join('\n');
// } else {
//   memoria_contexto = ""; // Sin historial previo
// }


// Extraer información del mensaje de WhatsApp
const message = wppData.messages[0]; // Primer mensaje del array
const contact = wppData.contacts[0]; // Primer contacto del array

//const chatInput = message.text.body;
//const chatInput = $input.first().json.mensajeUsuario
const chatInput = $('une_data_wpp').first().json.mensajeUsuario


const sessionId = message.from;
//const sessionId = message.from + "_9";
const userName = contact.profile.name || 'Cliente';
const celular = message.from;
const normalizedNumber = celular
  .replace(/^549/, "+54 "); 

// Formatear para el AI Agent
const formattedInput = {
  sessionId: sessionId,
  action: 'sendMessage',
  chatInput: chatInput,
//  etapa_actual,
  userContext: {
    name: userName,
    userId: message.from,
    chatId: message.from, // En WhatsApp el chatId suele ser el mismo que el userId
    phoneNumberId: wppData.metadata.phone_number_id,
    displayPhoneNumber: wppData.metadata.display_phone_number,
    telefono_origen: normalizedNumber,
    messageId: message.id,
    timestamp: message.timestamp,
    platform: 'whatsapp',
  //  contexto_historial: memoria_contexto    
  }
};

return { json: formattedInput };

// Validar y obtener el output del agente
const agentOutput = $input.first().json.output;

// VALIDACIÓN CRÍTICA: Detectar outputs vacíos o inválidos
const isEmptyOutput = !agentOutput || 
                      agentOutput.trim() === "" || 
                      agentOutput === "(No response was provided)" ||
                      agentOutput.includes("No response was provided");

// Si el output está vacío, generar respuesta de fallback
if (isEmptyOutput) {
  console.error("⚠️ Output vacío detectado del agente:", agentOutput);

  return [{ 
    json: { 
      output: "Disculpá, tuve un problema técnico procesando tu consulta. ¿Podrías repetir qué necesitás? 😊",
      error_detected: true,
      original_output: agentOutput
    } 
  }];
}

// Si el output es válido, retornarlo tal cual
return [{ 
  json: { 
    output: agentOutput,
    error_detected: false
  } 
}];

const mensajeUsuario = $input.first().json.mensaje_usuario

const data_wpp_text = $('WhatsApp Trigger').first().json

return [{ json: {
  ...data_wpp_text,
  mensajeUsuario
} }]

