const estadoJson = $input.first().json.propertyName || '{"human_takeover":false}';
const estado = JSON.parse(estadoJson);

return [{ json: { 
  sessionId: idSession,
  human_takeover: estado.human_takeover
}}];

const conversaciones = items[0].json.payload || [];
const INBOX_OBJETIVO = 8; // 👈 inbox nuevo

const encontrada = conversaciones.find(
  c => c.inbox_id === INBOX_OBJETIVO
);

if (!encontrada) {
  return [{
    json: {
      existe_conversacion: false
    }
  }];
}

return [{
  json: {
    existe_conversacion: true,
    conversation_id: encontrada.id
  }
}];

